class PantryRequest:
    VALID_PRIORITIES = {"low", "medium", "high"}

    def __init__(self, household, priority="medium", fulfilled=False):
        if not household.strip():
            raise ValueError("household is required")
        if priority not in self.VALID_PRIORITIES:
            raise ValueError("invalid priority")
        self.household = household
        self.priority = priority
        self.fulfilled = bool(fulfilled)

    def mark_fulfilled(self):
        self.fulfilled = True

    def is_open(self):
        return not self.fulfilled

    def summary(self):
        return f"{self.household} | priority={self.priority} | fulfilled={self.fulfilled}"

